// Copyright 2021 The Go Authors. All rights reserved.// Use of this source code is governed by a BSD-style// license that can be found in the LICENSE file.//go:build linux// +build linuxpackage uniximport (unsafe")// Helpers for dealing with ifreq since it contains a union and thus requires a// lot of unsafe.Pointer casts to use properly.// An Ifreq is a type-safe wrapper around the raw ifreq struct. An Ifreq// contains an interface name and a union of arbitrary data which can be// accessed using the Ifreq's methods. To create an Ifreq, use the NewIfreq// function.//// Use the Name method to access the stored interface name. The union data// fields can be get and set using the following methods://- Uint16/SetUint16: flags//- Uint32/SetUint32: ifindex, metric, mtutype Ifreq struct{ raw ifreq }// NewIfreq creates an Ifreq with the input network interface name after// validating the name does not exceed IFNAMSIZ-1 (trailing NULL required)// bytes. NewIfreq(name string) (*Ifreq, error) {/ Leave room for terminating NULL byte.f len(name) >= IFNAMSIZ {return nil, EINVALvr ifr ifreqopy(ifr.Ifrn[:], name)rturn &Ifreq{raw: ifr}, nil}// TODO(mdlayher): get/set methods for hardware address sockaddr, char array, etc.// Name returns the interface name associated with the Ifreq. (ifr *Ifreq) Name() string {eturn ByteSliceToString(ifr.raw.Ifrn[:])}// According to netdevice(7), only AF_INET addresses are returned for numerous// sockaddr ioctls. For convenience, we expose these as Inet4Addr since the Port// field and other data is always empty.// Inet4Addr returns the Ifreq union data from an embedded sockaddr as a C// in_addr/Go []byte (4-byte IPv4 address) value. If the sockaddr family is not// AF_INET, an error is returned. (ifr *Ifreq) Inet4Addr() ([]byte, error) {aw := *(*RawSockaddrInet4)(unsafe.Pointer(&ifr.raw.Ifru[:SizeofSockaddrInet4][0]))f raw.Family != AF_INET {// Cannot safely interpret raw.Addr bytes as an IPv4 address.return nil, EINVALrturn raw.Addr[:], nil}// SetInet4Addr sets a C in_addr/Go []byte (4-byte IPv4 address) value in an// embedded sockaddr within the Ifreq's union data. v must be 4 bytes in length// or an error will be returned. (ifr *Ifreq) SetInet4Addr(v []byte) error {f len(v) != 4 {return EINVALvr addr [4]byteopy(addr[:], v)ir.clear()(*RawSockaddrInet4)(unsafe.Pointer(&ifr.raw.Ifru[:SizeofSockaddrInet4][0]), = RawSockaddrInet4{// Always set IP family as ioctls would require it anyway.Family: AF_INET,Addr:addr,rturn nil}// Uint16 returns the Ifreq union data as a C short/Go uint16 value. (ifr *Ifreq) Uint16() uint16 {eturn *(*uint16)(unsafe.Pointer(&ifr.raw.Ifru[:2][0]))}// SetUint16 sets a C short/Go uint16 value as the Ifreq's union data. (ifr *Ifreq) SetUint16(v uint16) {fr.clear()(*uint16)(unsafe.Pointer(&ifr.raw.Ifru[:2][0])) = v}// Uint32 returns the Ifreq union data as a C int/Go uint32 value. (ifr *Ifreq) Uint32() uint32 {eturn *(*uint32)(unsafe.Pointer(&ifr.raw.Ifru[:4][0]))}// SetUint32 sets a C int/Go uint32 value as the Ifreq's union data. (ifr *Ifreq) SetUint32(v uint32) {fr.clear()(*uint32)(unsafe.Pointer(&ifr.raw.Ifru[:4][0])) = v}// clear zeroes the ifreq's union field to prevent trailing garbage data from// being sent to the kernel if an ifreq is reused. (ifr *Ifreq) clear() {or i := range ifr.raw.Ifru {ifr.raw.Ifru[i] = 0}// TODO(mdlayher): export as IfreqData? For now we can provide helpers such as// IoctlGetEthtoolDrvinfo which use these APIs under the hood.// An ifreqData is an Ifreq which carries pointer data. To produce an ifreqData,// use the Ifreq.withData method.type ifreqData struct {ame [IFNAMSIZ]byte/ A type separate from ifreq is required in order to comply with the/ unsafe.Pointer rules since the "pointer-ness" of data would not be/ preserved if it were cast into the byte array of a raw ifreq.ata unsafe.Pointer/ Pad to the same size as ifreq. [len(ifreq{}.Ifru) - SizeofPtr]byte}// withData produces an ifreqData with the pointer p set for ioctls which require// arbitrary pointer data. (ifr Ifreq) withData(p unsafe.Pointer) ifreqData {eturn ifreqData{name: ifr.raw.Ifrn,data: p,}